import { parseServerFormsValue } from '../../../models/server/forms/value.js';
import { serverSubmitLevelResultRequestSchema } from '../../../schemas/server/items/levelResult/submit.js';
import { parse } from '../../../utils/json.js';
import { handleError } from '../../error.js';
export const createServerSubmitLevelResultRouteHandler = (levelResult) => async ({ req, res, localize, ctx }) => {
    if (!levelResult.submitHandler) {
        res.status(404).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, serverSubmitLevelResultRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    const value = parseServerFormsValue(Object.fromEntries(new URLSearchParams(request.values)), levelResult.submits);
    if (!value) {
        res.status(400).end();
        return;
    }
    const response = await levelResult.submitHandler({ ...ctx, replay: request.replay, value });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
